%% P3_Exp03_label_dependent_residual_extrapolation.m
% Purpose:
% This script constructs the label-dependent residual-error extrapolation
% model for target-domain pack-level SOH prediction.
% It reads the nested-resampling residuals generated by
% P3_Exp01_NestedResampling_ErrorEvaluation.m, extracts empirical
% residual features for k = 5 to 21, fits k-dependent feature curves,
% extrapolates the residual-error model to k = 50, and exports the
% uncertainty model used by downstream economic optimization.


clear; clc; close all;

%% 1) Configuration
cfg = struct();

% Use the current script folder as the Part3 root folder.
script_dir = fileparts(mfilename('fullpath'));

if isempty(script_dir)
 script_dir = pwd;
end

% Root folders.
cfg.output_dir = fullfile(script_dir, 'Output');
cfg.results_dir = fullfile(cfg.output_dir, 'Results');

cfg.figure_dir = fullfile(script_dir, 'Figures');
cfg.ext_fig_dir = fullfile(cfg.figure_dir, 'Extended');

% Input file generated by Part3 Exp01.
% The primary path follows the new naming convention.
cfg.input_mat_primary = fullfile(cfg.results_dir, 'P3_Exp01_NestedResampling_Final.mat');

% Legacy fallback path for the existing long-running Main01 output.
% Keep this fallback to avoid rerunning the nested-resampling experiment.
cfg.input_mat_legacy = fullfile(cfg.output_dir, 'Result01_NestedResampling_Final.mat');

if exist(cfg.input_mat_primary, 'file')
 cfg.input_mat = cfg.input_mat_primary;
elseif exist(cfg.input_mat_legacy, 'file')
 cfg.input_mat = cfg.input_mat_legacy;
else
 error('Input file not found. Checked:\n%s\n%s', ...
 cfg.input_mat_primary, cfg.input_mat_legacy);
end

% Output tables and model file generated by Part3 Exp03.
cfg.param_csv = fullfile(cfg.results_dir, 'P3_Exp03_ResidualExtrapolation_Params_k5_k50.csv');
cfg.core_region_csv = fullfile(cfg.results_dir, 'P3_Exp03_CoreRegionFeatures_PM_PR_SigmaR_k5_k50.csv');
cfg.feature_csv = fullfile(cfg.results_dir, 'P3_Exp03_ResidualExtrapolation_EmpiricalFeatures_k5_k21.csv');
cfg.model_mat = fullfile(cfg.results_dir, 'P3_Exp03_ResidualExtrapolation_Model.mat');

% Output figures for Extended Data Fig. 3.
cfg.fig_RMSE = fullfile(cfg.ext_fig_dir,'ExD03b_RMSE_scaling_fit.fig');
cfg.png_RMSE = fullfile(cfg.ext_fig_dir, 'ExD03b_RMSE_scaling_fit.png');

cfg.fig_PR = fullfile(cfg.ext_fig_dir, 'ExD03c_PR_fit.fig');
cfg.png_PR = fullfile(cfg.ext_fig_dir, 'ExD03c_PR_fit.png');

cfg.fig_PM = fullfile(cfg.ext_fig_dir, 'ExD03d_PM_fit.fig');
cfg.png_PM = fullfile(cfg.ext_fig_dir, 'ExD03d_PM_fit.png');

cfg.fig_sigR = fullfile(cfg.ext_fig_dir, 'ExD03e_sigmaR_fit.fig');
cfg.png_sigR = fullfile(cfg.ext_fig_dir, 'ExD03e_sigmaR_fit.png');

cfg.dist_dir = fullfile(cfg.ext_fig_dir, 'ExD03a_residual_distribution_k05_to_k25');

% Empirical and extrapolation settings.
cfg.k_emp_min = 5;
cfg.k_emp_max = 21;
cfg.k_extrap_max = 50;
cfg.k_anchor = 21;
cfg.k_bridge_end = 26;

% Residual-generator settings.
% 'region_consistent' estimates the right-component weight w by jointly
% matching the fitted right-region probability and the target RMSE.
% 'legacy_proxy' reproduces the previous P_R-based proxy followed by the
% feasibility reduction loop. The model should normally use
% 'region_consistent'.
cfg.w_method = 'region_consistent';
cfg.min_sig_main = 0.0010;
cfg.w_solver_tolerance = 5e-4;

% The bridge uses probability mixing rather than pointwise averaging.
% A final RMSE calibration is applied only in the bridge interval.
cfg.bridge_method = 'probability_mixture_rmse_calibrated';

% Monte Carlo and density settings.
cfg.N_sim = 100000;
cfg.kde_bw = 0.0055;
cfg.hist_bins = 70;
cfg.png_resolution = 600;

rng(42);

% Create output folders if they do not exist.
if ~exist(cfg.output_dir, 'dir')
 mkdir(cfg.output_dir);
end

if ~exist(cfg.results_dir, 'dir')
 mkdir(cfg.results_dir);
end

if ~exist(cfg.figure_dir, 'dir')
 mkdir(cfg.figure_dir);
end

if ~exist(cfg.ext_fig_dir, 'dir')
 mkdir(cfg.ext_fig_dir);
end

if ~exist(cfg.dist_dir, 'dir')
 mkdir(cfg.dist_dir);
end

fprintf('================ Part3 Exp03 residual-error extrapolation ================\n');
fprintf('Input result file: %s\n', cfg.input_mat);
fprintf('Output model file: %s\n', cfg.model_mat);
fprintf('Extended figure folder: %s\n', cfg.ext_fig_dir);

%% 2) Define residual regions
region = struct();

region.main = [-0.012, 0.015];
region.valley = [ 0.015, 0.028];
region.right = [ 0.028, 0.052];
region.left = [-0.060, -0.020];

%% 3) Load nested-resampling results and pool all-inner residuals
if ~exist(cfg.input_mat, 'file')
 error('Input file not found: %s', cfg.input_mat);
end

S = load(cfg.input_mat);

required_vars = { ...
 'train_size_list', ...
 'all_inner_errs'};

for i = 1:numel(required_vars)
 if ~isfield(S, required_vars{i})
 error('Required variable "%s" was not found in %s.', ...
 required_vars{i}, cfg.input_mat);
 end
end

train_size_list = S.train_size_list(:);
all_inner_errs = S.all_inner_errs;

k_emp = (cfg.k_emp_min:cfg.k_emp_max)';
num_k_emp = numel(k_emp);

err_cell = cell(num_k_emp, 1);

num_outer_used_list = zeros(num_k_emp, 1);
num_inner_used_list = zeros(num_k_emp, 1);
num_residual_used_list = zeros(num_k_emp, 1);

for i = 1:num_k_emp

 idx_k = find(train_size_list == k_emp(i), 1);

 if isempty(idx_k)
 error('k = %d was not found in train_size_list.', k_emp(i));
 end

 err_all = [];
 num_outer_used = 0;
 num_inner_used = 0;

 for mc = 1:size(all_inner_errs, 2)

 E = all_inner_errs{idx_k, mc};

 if isempty(E)
 continue;
 end

 E = double(E);

 if isempty(E) || all(~isfinite(E(:)))
 continue;
 end

 % Each column corresponds to one inner repetition.
 % Each row corresponds to one test pack in the current outer split.
 num_outer_used = num_outer_used + 1;
 num_inner_used = num_inner_used + size(E, 2);

 E = E(isfinite(E));
 err_all = [err_all; E(:)]; %#ok<AGROW>
 end

 if isempty(err_all)
 error('No valid all-inner residual samples were found for k = %d.', k_emp(i));
 end

 err_cell{i} = double(err_all(:));

 num_outer_used_list(i) = num_outer_used;
 num_inner_used_list(i) = num_inner_used;
 num_residual_used_list(i) = numel(err_all);
end

fprintf('All-inner residuals extracted for k = %d to %d.\n', ...
 cfg.k_emp_min, cfg.k_emp_max);

%% 4) Extract empirical residual-region features
% Raw empirical features are retained separately from the smoothed values
% used as fitting inputs. This prevents the moving-average operation from
% silently replacing the measured all-inner residual features.

P_M_raw = zeros(num_k_emp, 1);
P_R_raw = zeros(num_k_emp, 1);
P_V_raw = zeros(num_k_emp, 1);
P_L_raw = zeros(num_k_emp, 1);

mu_M_raw = zeros(num_k_emp, 1);
mu_R_raw = zeros(num_k_emp, 1);

sig_M_raw = zeros(num_k_emp, 1);
sig_R_raw = zeros(num_k_emp, 1);

rmseK = zeros(num_k_emp, 1);

for i = 1:num_k_emp

 e = err_cell{i};

 rmseK(i) = sqrt(mean(e.^2));

 % Identify residual samples within each predefined diagnostic region.
 idx_main = (e >= region.main(1)) & (e < region.main(2));
 idx_right = (e >= region.right(1)) & (e < region.right(2));
 idx_valley = (e >= region.valley(1)) & (e < region.valley(2));
 idx_left = (e >= region.left(1)) & (e < region.left(2));

 P_M_raw(i) = mean(idx_main);
 P_R_raw(i) = mean(idx_right);
 P_V_raw(i) = mean(idx_valley);
 P_L_raw(i) = mean(idx_left);

 % Main residual mode descriptors.
 eM = e(idx_main);

 if isempty(eM)
 eM = e;
 end

 mu_M_raw(i) = median(eM);

 sM = iqr(eM) / 1.349;

 if numel(eM) < 4 || sM == 0 || isnan(sM)
 sM = std(eM);
 end

 sig_M_raw(i) = max([sM, 1e-4]);

 % Positive right-tail descriptors.
 eR = e(idx_right);

 if ~isempty(eR)

 mu_R_raw(i) = mean(eR);

 sR = iqr(eR) / 1.349;

 if numel(eR) < 4 || sR == 0 || isnan(sR)
 sR = std(eR);
 end

 sig_R_raw(i) = max([sR, 1e-4]);

 else

 mu_R_raw(i) = mean(region.right);
 sig_R_raw(i) = 0.005;
 end
end

% Three-point moving averages are used only as fitting inputs. The raw
% empirical estimates remain available in the output tables and figures.
P_R_fit_input = min(max(smoothdata(P_R_raw, 'movmean', 3), 0), 0.40);
P_M_fit_input = min(max(smoothdata(P_M_raw, 'movmean', 3), 0), 1.00);
mu_M_fit_input = smoothdata(mu_M_raw, 'movmean', 3);
mu_R_fit_input = smoothdata(mu_R_raw, 'movmean', 3);
sig_M_fit_input = max(smoothdata(sig_M_raw, 'movmean', 3), 1e-4);
sig_R_fit_input = max(smoothdata(sig_R_raw, 'movmean', 3), 1e-4);

% Compatibility aliases. These retain the direct empirical meanings.
P_M = P_M_raw;
P_R = P_R_raw;
P_V = P_V_raw;
P_L = P_L_raw;
mu_M = mu_M_raw;
mu_R = mu_R_raw;
sig_M = sig_M_raw;
sig_R = sig_R_raw;

EmpiricalFeatureTable = table( ...
 k_emp, ...
 num_outer_used_list, ...
 num_inner_used_list, ...
 num_residual_used_list, ...
 rmseK, ...
 P_M_raw, ...
 P_M_fit_input, ...
 P_R_raw, ...
 P_R_fit_input, ...
 P_V_raw, ...
 P_L_raw, ...
 mu_M_raw, ...
 mu_M_fit_input, ...
 sig_M_raw, ...
 sig_M_fit_input, ...
 mu_R_raw, ...
 mu_R_fit_input, ...
 sig_R_raw, ...
 sig_R_fit_input, ...
 'VariableNames', { ...
 'k', ...
 'N_outer_runs', ...
 'N_inner_runs_all_inner', ...
 'N_residuals_all_inner', ...
 'RMSE_empirical', ...
 'P_main_raw', ...
 'P_main_fit_input', ...
 'P_right_raw', ...
 'P_right_fit_input', ...
 'P_valley_raw', ...
 'P_left_raw', ...
 'mu_main_raw', ...
 'mu_main_fit_input', ...
 'sig_main_raw', ...
 'sig_main_fit_input', ...
 'mu_right_raw', ...
 'mu_right_fit_input', ...
 'sig_right_raw', ...
 'sig_right_fit_input'});

writetable(EmpiricalFeatureTable, cfg.feature_csv);

fprintf('Empirical feature table saved: %s\n', cfg.feature_csv);

%% 4.1 Fit RMSE scaling law for extrapolation
% Fit the power-law model: RMSE(k) = a * k^(-b) + c.
% The fitted curve is used consistently for RMSE extrapolation and plotting.

x_rmse = k_emp(:);
y_rmse = rmseK(:);

valid_rmse = isfinite(x_rmse) & isfinite(y_rmse) & (y_rmse > 0);
x_rmse = x_rmse(valid_rmse);
y_rmse = y_rmse(valid_rmse);

ft_RMSE = fittype('a * x^(-b) + c', ...
 'independent', 'x', ...
 'dependent', 'y');

opts_RMSE = fitoptions('Method', 'NonlinearLeastSquares');
opts_RMSE.Display = 'Off';
opts_RMSE.StartPoint = [0.1, 0.5, min(y_rmse)];
opts_RMSE.Lower = [0, 0, 0];

[fit_RMSE, gof_RMSE] = fit(x_rmse, y_rmse, ft_RMSE, opts_RMSE);

a_RMSE = fit_RMSE.a;
b_RMSE = fit_RMSE.b;
c_RMSE = fit_RMSE.c;
R2_RMSE = gof_RMSE.rsquare;

fprintf('\n================ RMSE scaling-law fitting ================\n');
fprintf('RMSE(k) = %.6f * k^(-%.6f) + %.6f\n', ...
 a_RMSE, b_RMSE, c_RMSE);
fprintf('RMSE scaling R2 = %.4f\n', R2_RMSE);
fprintf('==========================================================\n');

%% 5) Define robust Huber loss
huber_core = @(r, d) ...
 (abs(r) <= d) .* (0.5 * r.^2) + ...
 (abs(r) > d) .* (d .* (abs(r) - 0.5 * d));

huber_loss = @(y, yhat) ...
 sum(huber_core(y - yhat, 1.5 * max(mad(y - yhat, 1), 1e-6)));

%% 6) Fit parametric curves for empirical distribution features
% The fitted functions describe the smoothed empirical feature trajectories.
% Raw-feature R-squared values are also calculated below for transparency.

k0 = min(k_emp);

opt = optimset( ...
 'Display', 'off', ...
 'MaxFunEvals', 6000, ...
 'MaxIter', 6000);

% 6.1 Fit P_R with exponential decay toward a plateau.
PR0 = P_R_fit_input(1);
cR_lb = 0.00;
cR_ub = 0.08;

bnd_cR = @(c) min(max(c, cR_lb), cR_ub);
pen_cR = @(c) ...
 1e6 * (c < cR_lb) .* (cR_lb - c).^2 + ...
 1e6 * (c > cR_ub) .* (c - cR_ub).^2;

yhat_PR = @(p, x) ...
 bnd_cR(p(2)) + ...
 (PR0 - bnd_cR(p(2))) .* exp(-exp(p(1)) .* (x - k0));

obj_PR = @(p) huber_loss(P_R_fit_input, yhat_PR(p, k_emp)) + pen_cR(p(2));

p_optR = fminsearch(obj_PR, [log(0.18); min(P_R_fit_input(end), 0.05)], opt);

bR_opt = exp(p_optR(1));
cR_opt = bnd_cR(p_optR(2));

% 6.2 Fit P_M with exponential growth toward saturation.
PM0 = P_M_fit_input(1);

cM_lb = max(P_M_fit_input);
cM_ub = max(0.95, cM_lb + 1e-4);

bnd_cM = @(c) min(max(c, cM_lb), cM_ub);
pen_cM = @(c) ...
 1e6 * (c < cM_lb) .* (cM_lb - c).^2 + ...
 1e6 * (c > cM_ub) .* (c - cM_ub).^2;

yhat_PM = @(p, x) ...
 bnd_cM(p(2)) - ...
 (bnd_cM(p(2)) - PM0) .* exp(-exp(p(1)) .* (x - k0));

obj_PM = @(p) huber_loss(P_M_fit_input, yhat_PM(p, k_emp)) + pen_cM(p(2));

p_optM = fminsearch(obj_PM, [log(0.12); max(0.8, max(P_M_fit_input))], opt);

bM_opt = exp(p_optM(1));
cM_opt = bnd_cM(p_optM(2));

% 6.3 Fit mu_M with exponential shrinkage toward zero.
mask_muM = (k_emp >= 7) & ...
 (k_emp <= cfg.k_anchor) & ...
 isfinite(mu_M_fit_input);

if sum(mask_muM) < 3
 mask_muM = isfinite(mu_M_fit_input);
end

xm = k_emp(mask_muM);
ym = mu_M_fit_input(mask_muM);

idx_anchor = find(k_emp == cfg.k_anchor, 1);
muM_anchor = mu_M_fit_input(idx_anchor);

yhat_muM = @(p, x) ...
 muM_anchor .* exp(-exp(p(1)) .* (x - cfg.k_anchor));

obj_muM = @(p) huber_loss(ym, yhat_muM(p, xm));

p_opt_muM = fminsearch(obj_muM, log(0.08), opt);

a_muM = exp(p_opt_muM(1));

% 6.4 Fit sig_R with positive exponential decay.
mask_sigR = (k_emp >= cfg.k_emp_min) & ...
 (k_emp <= cfg.k_anchor) & ...
 (sig_R_fit_input > 0) & ...
 isfinite(sig_R_fit_input);

if sum(mask_sigR) < 3
 error('Not enough valid sigma_R samples for curve fitting.');
end

xs = k_emp(mask_sigR);
ys = sig_R_fit_input(mask_sigR);

k0_s = min(xs);

c_lb_s = 0.0003;
c_ub_s = 0.0012;

bnd_cs = @(c) min(max(c, c_lb_s), c_ub_s);
pen_cs = @(c) ...
 1e6 * (c < c_lb_s) .* (c_lb_s - c).^2 + ...
 1e6 * (c > c_ub_s) .* (c - c_ub_s).^2;

yhat_sigR = @(p, x) ...
 bnd_cs(p(3)) + exp(p(1)) .* exp(-exp(p(2)) .* (x - k0_s));

obj_sigR = @(p) huber_loss(ys, yhat_sigR(p, xs)) + pen_cs(p(3));

p_opt_sigR = fminsearch( ...
 obj_sigR, ...
 [log(max(ys) - min(ys) + 1e-6); log(0.18); min(ys)], ...
 opt);

A_sigR = exp(p_opt_sigR(1));
b_sigR = exp(p_opt_sigR(2));
c_sigR = bnd_cs(p_opt_sigR(3));

%% 7) Compute fitting R-squared values
% The primary fitting R-squared values are evaluated against the smoothed
% feature trajectories used for fitting. Raw-feature R-squared values are
% retained separately to show agreement with the unsmoothed observations.

PR_fit_at_emp = yhat_PR(p_optR, k_emp);
PM_fit_at_emp = yhat_PM(p_optM, k_emp);
muM_fit_at_emp = yhat_muM(p_opt_muM, xm);
sigR_fit_at_emp = yhat_sigR(p_opt_sigR, xs);

R2_PR_fit_input = local_r2(P_R_fit_input, PR_fit_at_emp);
R2_PM_fit_input = local_r2(P_M_fit_input, PM_fit_at_emp);
R2_muM_fit_input = local_r2(ym, muM_fit_at_emp);
R2_sigR_fit_input = local_r2(ys, sigR_fit_at_emp);

R2_PR_raw = local_r2(P_R_raw, PR_fit_at_emp);
R2_PM_raw = local_r2(P_M_raw, PM_fit_at_emp);
R2_muM_raw = local_r2(mu_M_raw(mask_muM), muM_fit_at_emp);
R2_sigR_raw = local_r2(sig_R_raw(mask_sigR), sigR_fit_at_emp);

% Compatibility aliases used in existing manuscript-export logic.
R2_PR = R2_PR_fit_input;
R2_PM = R2_PM_fit_input;
R2_muM = R2_muM_fit_input;
R2_sigR = R2_sigR_fit_input;

fprintf('\n================ Feature-fitting results ================\n');
fprintf('P_R(k): fit-input R2 = %.4f | raw R2 = %.4f\n', R2_PR_fit_input, R2_PR_raw);
fprintf('P_M(k): fit-input R2 = %.4f | raw R2 = %.4f\n', R2_PM_fit_input, R2_PM_raw);
fprintf('mu_M(k): fit-input R2 = %.4f | raw R2 = %.4f\n', R2_muM_fit_input, R2_muM_raw);
fprintf('sigma_R(k): fit-input R2 = %.4f | raw R2 = %.4f\n', R2_sigR_fit_input, R2_sigR_raw);
fprintf('=========================================================\n');

%% 8) Construct target feature curves for k = 5 to 50
k_vals = (cfg.k_emp_min:cfg.k_extrap_max)';
num_k_vals = numel(k_vals);

% Fixed-region probability curve. P_R remains a diagnostic region mass and
% is not directly assigned to the Gaussian-mixture component weight.
PR_curve = min(max( ...
 cR_opt + (PR0 - cR_opt) .* exp(-bR_opt .* (k_vals - k0)), ...
 0), 0.40);

PM_curve = cM_opt - (cM_opt - PM0) .* exp(-bM_opt .* (k_vals - k0));
PM_curve = min(max(PM_curve, 0), 1);

muM_curve = muM_anchor .* exp(-a_muM .* (k_vals - cfg.k_anchor));

mask_muR_tail = (k_emp >= 15) & (k_emp <= cfg.k_anchor);

if any(mask_muR_tail)
 muR_const = median(mu_R_fit_input(mask_muR_tail), 'omitnan');
else
 muR_const = median(mu_R_fit_input, 'omitnan');
end

muR_curve = muR_const * ones(num_k_vals, 1);

sigR_curve = max( ...
 c_sigR + A_sigR .* exp(-b_sigR .* (k_vals - k0_s)), ...
 1e-6);

SigmaR_width_curve = 2 * sigR_curve;
RightLine_Lower_curve = muR_curve - sigR_curve;
RightLine_Upper_curve = muR_curve + sigR_curve;

% Empirical RMSE values are retained for k = 5 to 21. The fitted power-law
% curve is used only beyond the empirical label range.
rmse_target = zeros(num_k_vals, 1);

for i = 1:num_k_vals

 if k_vals(i) <= cfg.k_emp_max
 idx_emp = find(k_emp == k_vals(i), 1);
 rmse_target(i) = rmseK(idx_emp);
 else
 rmse_target(i) = fit_RMSE(k_vals(i));
 end
end

if any(~isfinite(rmse_target)) || any(rmse_target <= 0)
 error('Invalid RMSE target values were generated.');
end

%% 8.1 Legacy P_R proxy for comparison only
% This reproduces the previous procedure: w starts from P_R and is reduced
% by repeated multiplication by 0.92 until the target RMSE can support a
% minimum main-mode width. These arrays are retained only for diagnosis.

w_proxy_curve = PR_curve;
w_legacy_effective_curve = zeros(num_k_vals, 1);
sigM_legacy_curve = zeros(num_k_vals, 1);
legacy_adjustment_ratio = zeros(num_k_vals, 1);
legacy_was_adjusted = false(num_k_vals, 1);

for i = 1:num_k_vals

 rt = rmse_target(i);
 w_initial = w_proxy_curve(i);
 muM0 = muM_curve(i);
 muR0 = muR_curve(i);
 sigR0 = sigR_curve(i);

 w_eff = w_initial;

 for it = 1:40

 num = rt^2 ...
 - w_eff * (sigR0^2 + muR0^2) ...
 - (1 - w_eff) * muM0^2;

 den = max(1 - w_eff, 1e-8);

 if (num / den) > cfg.min_sig_main^2
 break;
 end

 w_eff = 0.92 * w_eff;
 end

 w_legacy_effective_curve(i) = w_eff;
 legacy_adjustment_ratio(i) = w_eff / max(w_initial, 1e-12);
 legacy_was_adjusted(i) = abs(w_eff - w_initial) > 1e-12;

 num = rt^2 ...
 - w_eff * (sigR0^2 + muR0^2) ...
 - (1 - w_eff) * muM0^2;

 sigM_legacy_curve(i) = sqrt(max( ...
 num / max(1 - w_eff, 1e-8), ...
 cfg.min_sig_main^2));
end

%% 8.2 Region-consistent estimation of w and sigma_M
% The method solves for w using two requirements:
% (1) the two-mode distribution matches the target RMSE, and
% (2) its probability inside the fixed right region matches P_R(k).
% This separates the observed region probability P_R from the latent
% Gaussian-component weight w and removes the silent 0.92 adjustment loop.

w_region_curve = zeros(num_k_vals, 1);
sigM_region_curve = zeros(num_k_vals, 1);
PR_model_from_w_curve = zeros(num_k_vals, 1);
w_feasible_max_curve = zeros(num_k_vals, 1);
w_solver_abs_error = zeros(num_k_vals, 1);
w_solver_status = cell(num_k_vals, 1);

for i = 1:num_k_vals

 [w_region_curve(i), ...
 sigM_region_curve(i), ...
 PR_model_from_w_curve(i), ...
 w_feasible_max_curve(i), ...
 w_solver_status{i}] = local_solve_region_consistent_weight( ...
 PR_curve(i), ...
 rmse_target(i), ...
 muM_curve(i), ...
 muR_curve(i), ...
 sigR_curve(i), ...
 region.right, ...
 cfg.min_sig_main);

 w_solver_abs_error(i) = abs(PR_model_from_w_curve(i) - PR_curve(i));
end

switch lower(cfg.w_method)

 case 'region_consistent'
 w_curve = w_region_curve;
 sigM_curve = sigM_region_curve;

 case 'legacy_proxy'
 w_curve = w_legacy_effective_curve;
 sigM_curve = sigM_legacy_curve;

 otherwise
 error('Unsupported cfg.w_method: %s', cfg.w_method);
end

fprintf('\n================ Right-component weight diagnosis ================\n');
fprintf('Selected method: %s\n', cfg.w_method);
fprintf('Legacy method adjusted w at %d of %d k values.\n', ...
 sum(legacy_was_adjusted), num_k_vals);
fprintf('Maximum region-consistent |P_R(model)-P_R(target)| = %.6f\n', ...
 max(w_solver_abs_error));

idx_anchor_full = find(k_vals == cfg.k_anchor, 1);
fprintf('At k = %d: P_R = %.6f, w_region = %.6f, w_legacy = %.6f\n', ...
 cfg.k_anchor, ...
 PR_curve(idx_anchor_full), ...
 w_region_curve(idx_anchor_full), ...
 w_legacy_effective_curve(idx_anchor_full));
fprintf('=================================================================\n');

if any(w_solver_abs_error(k_vals >= cfg.k_anchor) > cfg.w_solver_tolerance)
 warning(['The region-consistent generator does not exactly reproduce ' ...
 'P_R for some k values at or above the empirical anchor. ' ...
 'Inspect the diagnostic table before downstream optimization.']);
end

%% 9) Generate empirical, bridged and extrapolated residual distributions
% Common random numbers are used across k to reduce Monte Carlo noise when
% comparing adjacent label sizes.

base_u = rand(cfg.N_sim, 1);
base_z = randn(cfg.N_sim, 1);
base_pick = rand(cfg.N_sim, 1);
base_bridge = rand(cfg.N_sim, 1);

saved_noise_for_plot = cell(num_k_vals, 1);
err_anchor = err_cell{k_emp == cfg.k_anchor};

source_type = cell(num_k_vals, 1);
bridge_alpha_curve = zeros(num_k_vals, 1);
bridge_rmse_scale_curve = ones(num_k_vals, 1);
RMSE_generated = zeros(num_k_vals, 1);
P_R_generated = zeros(num_k_vals, 1);
P_M_generated = zeros(num_k_vals, 1);

for i = 1:num_k_vals

 k_now = k_vals(i);

 % Parametric two-mode residual sample.
 isR = base_pick < w_curve(i);

 e_par = zeros(cfg.N_sim, 1);
 e_par(~isR) = muM_curve(i) + sigM_curve(i) .* base_z(~isR);
 e_par(isR) = muR_curve(i) + sigR_curve(i) .* base_z(isR);

 if k_now <= cfg.k_anchor

 % Empirical bootstrap in the observed label range.
 e_data = sort(err_cell{k_emp == k_now});
 p = ((1:numel(e_data))' - 0.5) / numel(e_data);
 e_sample = interp1(p, e_data, base_u, 'linear', 'extrap');
 source_type{i} = 'Empirical';

 elseif k_now < cfg.k_bridge_end

 % Probability mixture between the empirical anchor and the
 % k-specific parametric distribution. This avoids the artificial
 % variance contraction caused by pointwise residual averaging.
 t = (k_now - cfg.k_anchor) / (cfg.k_bridge_end - cfg.k_anchor);
 alpha = 3 * (min(max(t, 0), 1))^2 ...
 - 2 * (min(max(t, 0), 1))^3;

 bridge_alpha_curve(i) = alpha;

 e_data = sort(err_anchor);
 p = ((1:numel(e_data))' - 0.5) / numel(e_data);
 e_emp = interp1(p, e_data, base_u, 'linear', 'extrap');

 use_parametric = base_bridge < alpha;
 e_sample = e_emp;
 e_sample(use_parametric) = e_par(use_parametric);

 % The bridge is calibrated to the fitted RMSE trajectory. This
 % calibration is not applied to empirical or fully extrapolated k.
 rmse_before = sqrt(mean(e_sample.^2));
 bridge_rmse_scale_curve(i) = ...
 rmse_target(i) / max(rmse_before, 1e-12);
 e_sample = e_sample .* bridge_rmse_scale_curve(i);

 source_type{i} = 'Bridged';

 else

 % Fully extrapolated parametric distribution.
 e_sample = e_par;
 source_type{i} = 'Extrapolated';
 end

 saved_noise_for_plot{i} = e_sample;

 RMSE_generated(i) = sqrt(mean(e_sample.^2));
 P_R_generated(i) = mean( ...
 e_sample >= region.right(1) & e_sample < region.right(2));
 P_M_generated(i) = mean( ...
 e_sample >= region.main(1) & e_sample < region.main(2));
end

