%% Local helper functions
function R2 = local_r2(y, yhat)
% Compute R-squared with numerical protection.

y = y(:);
yhat = yhat(:);

valid = isfinite(y) & isfinite(yhat);
y = y(valid);
yhat = yhat(valid);

if numel(y) < 2
 R2 = NaN;
 return;
end

sst = sum((y - mean(y)).^2);
sse = sum((y - yhat).^2);

if sst < 1e-12
 R2 = NaN;
else
 R2 = 1 - sse / sst;
end
end

function [w_opt, sigM_opt, PR_model, w_feasible_max, status] = ...
 local_solve_region_consistent_weight( ...
 PR_target, rmse_target, muM, muR, sigR, right_region, min_sigM)
% Estimate the latent right-component weight w while matching both the
% target second moment and the target probability inside the fixed right
% diagnostic interval.

PR_target = min(max(PR_target, 0), 1);
rmse_target = max(rmse_target, 1e-12);
min_sigM = max(min_sigM, 1e-8);

second_right = sigR^2 + muR^2;
second_main_min = min_sigM^2 + muM^2;

if rmse_target^2 <= second_main_min
 w_feasible_max = 0;
 w_opt = 0;
 sigM_opt = sqrt(max(rmse_target^2 - muM^2, min_sigM^2));
 PR_model = local_region_probability_mixture( ...
 w_opt, muM, sigM_opt, muR, sigR, right_region);
 status = 'No positive-w solution: main-mode floor active';
 return;
end

if second_right > second_main_min
 w_feasible_max = ...
 (rmse_target^2 - second_main_min) / ...
 (second_right - second_main_min);
else
 w_feasible_max = 0.999;
end

w_feasible_max = min(max(w_feasible_max, 0), 0.999);

if w_feasible_max <= 1e-12
 w_opt = 0;
 sigM_opt = sqrt(max(rmse_target^2 - muM^2, min_sigM^2));
 PR_model = local_region_probability_mixture( ...
 w_opt, muM, sigM_opt, muR, sigR, right_region);
 status = 'Boundary solution: w = 0';
 return;
end

objective = @(w) local_region_probability_error( ...
 w, PR_target, rmse_target, muM, muR, sigR, right_region, min_sigM);

[w_opt, ~] = fminbnd(objective, 0, w_feasible_max, ...
 optimset('Display', 'off', 'TolX', 1e-10));

sigM_opt = local_sigma_main_from_rmse( ...
 w_opt, rmse_target, muM, muR, sigR, min_sigM);

PR_model = local_region_probability_mixture( ...
 w_opt, muM, sigM_opt, muR, sigR, right_region);

if w_opt < 1e-7
 status = 'Boundary solution near w = 0';
elseif abs(w_opt - w_feasible_max) < 1e-7
 status = 'Boundary solution near feasible maximum';
else
 status = 'Interior solution';
end
end

function value = local_region_probability_error( ...
 w, PR_target, rmse_target, muM, muR, sigR, right_region, min_sigM)
% Squared discrepancy between the mixture region probability and target P_R.

sigM = local_sigma_main_from_rmse( ...
 w, rmse_target, muM, muR, sigR, min_sigM);

PR_model = local_region_probability_mixture( ...
 w, muM, sigM, muR, sigR, right_region);

scale = max(PR_target, 0.01);
value = ((PR_model - PR_target) / scale)^2;
end

function sigM = local_sigma_main_from_rmse( ...
 w, rmse_target, muM, muR, sigR, min_sigM)
% Back-calculate the main-component width from the target second moment.

num = rmse_target^2 ...
 - w * (sigR^2 + muR^2) ...
 - (1 - w) * muM^2;

den = max(1 - w, 1e-12);
sigM = sqrt(max(num / den, min_sigM^2));
end

function PR_model = local_region_probability_mixture( ...
 w, muM, sigM, muR, sigR, right_region)
% Probability that a two-normal mixture falls inside the fixed right region.

lower = right_region(1);
upper = right_region(2);

qM = normcdf(upper, muM, sigM) - normcdf(lower, muM, sigM);
qR = normcdf(upper, muR, sigR) - normcdf(lower, muR, sigR);

PR_model = (1 - w) * qM + w * qR;
end

function local_save_figure(fig_handle, fig_file, png_file, resolution)
% Save a figure as both FIG and PNG files.

out_dir = fileparts(fig_file);

if ~exist(out_dir, 'dir')
 mkdir(out_dir);
end

savefig(fig_handle, fig_file);
exportgraphics(fig_handle, png_file, 'Resolution', resolution);

fprintf('[Figure] Saved: %s\n', png_file);
end